draw(O--5.5*V/abs(V));
draw(O--3*I, Arrow3(6));
draw(O--3*J, Arrow3(6));
draw(O--3*K, Arrow3(6));

label("$x$", 3.2*I);
label("$y$", 3.2*J);
label("$z$", 3.2*K);
dot("$P$", 5.5*V/abs(V), NE);
